import java.util.*

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val INF = Long.MAX_VALUE
    val dist = Array(m) { Array(n) { Array(k.toInt() + 1) { INF } } }
    dist[0][0][0] = 0L
    val pq = PriorityQueue<MutableList<Long>>(Comparator { a, b -> a[0].compareTo(b[0]) })
    val initialState = mutableListOf(0L, 0L, 0L, 0L)
    pq.add(initialState)
    while (pq.isNotEmpty()) {
        val current = pq.poll()
        val cost = current[0]
        val i = current[1].toInt()
        val j = current[2].toInt()
        val t = current[3].toInt()
        if (i == m - 1 && j == n - 1) return cost
        if (cost > dist[i][j][t]) continue
        // Regular moves: right
        if (j + 1 < n) {
            val newCost = cost + grid[i][j + 1]
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost
                val newState = mutableListOf(newCost, i.toLong(), (j + 1).toLong(), t.toLong())
                pq.add(newState)
            }
        }
        // Regular moves: down
        if (i + 1 < m) {
            val newCost = cost + grid[i + 1][j]
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost
                val newState = mutableListOf(newCost, (i + 1).toLong(), j.toLong(), t.toLong())
                pq.add(newState)
            }
        }
        // Teleportation
        if (t < k.toInt()) {
            val currentVal = grid[i][j]
            for (x in 0 until m) {
                for (y in 0 until n) {
                    if (grid[x][y] <= currentVal) {
                        val newCost = cost
                        if (newCost < dist[x][y][t + 1]) {
                            dist[x][y][t + 1] = newCost
                            val newState = mutableListOf(newCost, x.toLong(), y.toLong(), (t + 1).toLong())
                            pq.add(newState)
                        }
                    }
                }
            }
        }
    }
    return -1
}
